import{z as e,b as c,c as V,i as o}from"./index-dc5fff9e.js";const b="/assets/npn01-6ed70c62.png",r={class:"markdown-body"},s=o('<h4>1. 三极管</h4><table><thead><tr><th>类型</th><th>截至区</th><th>放大区</th><th>饱和区</th></tr></thead><tbody><tr><td>NPN</td><td>Vbe &lt; Von,Vce = Vcc</td><td>Vbe &gt;= Von,Vbe &lt;= Vce</td><td>Vbe &gt; Von,Vbe &gt;= Vce</td></tr><tr><td>PNP</td><td>Veb &lt; Von,Vec = Vcc</td><td>Veb &gt;= Von,Veb &lt;= Vec</td><td>Veb &gt; Von,Veb &gt;= Vec</td></tr></tbody></table><p>NPN:<br> 放大状态：发射结(Vbe)正偏，集电结(Vcb)反偏<br> 饱和状态：发射结(Vbe)正偏，集电结(Vcb)正偏<br> 截止状态：发射结(Vbe)反偏，集电结(Vcb)反偏</p><p>电流关系：<br> Ie = Ic + Ib,Ic = βIb<br> Ie = (Vbg - Vbe)/Re</p><ul><li>Vbe是发射结BE的饱和电压。</li><li>Re是发射极处连接的对地电阻</li></ul><p>Ib = Ie / (放大倍数+1)<br> Vc = Vcc - Ie * Rc</p><ul><li>Rc是集电极处连接的对地电阻。<br><img src="'+b+'" width="10%" style="margin-left:10%;"></li></ul><hr><h4>2. MOSTFET</h4><p>饱和区：</p><ul><li>NMOS：Vgs&gt;Vth (低端驱动)</li><li>PMOS：Vgs&lt;Vth (高端驱动)</li></ul><p>Vgs 与 Von 成反比</p><p>柏林少女</p>',13),d=[s],h={title:"电子相关资料",series:"techs",modtime:"2023/12/07"},a="",m=e({__name:"blog",setup(l,{expose:t}){return t({frontmatter:{title:"电子相关资料",series:"techs",modtime:"2023/12/07"},excerpt:void 0}),(i,n)=>(c(),V("div",r,d))}});export{m as default,a as excerpt,h as frontmatter};
